import React, { useState } from 'react';
import './assets/styles/global.css';

// HÄR ÄR MAGIN: Vi hämtar in ditt nya "rum"
import ConvoyView from './features/convoy/ConvoyView';

function App() {
  const [showAssistant, setShowAssistant] = useState(false);
  const [activeTab, setActiveTab] = useState('home');

  // --- DATA FÖR HEM OCH LOGGBOK ---
  const stats = [
    { label: 'Km idag', value: '124', icon: '🧭' },
    { label: 'Körtid', value: '2h 15m', icon: '⚡' },
    { label: 'Stopp', value: '3', icon: '📍' },
  ];

  const logbookEntries = [
    { id: 1, time: 'Idag, 14:30', title: 'Lunch vid sjön', type: 'stopp', icon: '🍽️', desc: 'Solen sken, vi käkade mackor och njöt av utsikten.' },
    { id: 2, time: 'Idag, 10:15', title: 'Tankning & Kaffe', type: 'service', icon: '☕', desc: 'Snabbstopp innan bergen.' },
    { id: 3, time: 'Igår, 19:00', title: 'Nattplats: Skogsbrynet', type: 'natt', icon: '🌙', desc: 'Helt tyst, bara vi och ugglorna.' }
  ];

  // --- VYER ---
  const renderContent = () => {

    // 1. HEM-VYN
    if (activeTab === 'home') {
      return (
        <div style={{ padding: '20px' }} className="animate-fade-in">
          <header style={{ marginBottom: '30px' }}>
            <h1 style={{ fontSize: '24px', fontWeight: 'bold', color: '#2D5A27' }}>Hej Buddy! 🚐</h1>
            <p style={{ color: '#636E72' }}>Solen går ner om 3 timmar. Letar vi nattplats?</p>
          </header>

          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '10px', marginBottom: '30px' }}>
            {stats.map((stat, i) => (
              <div key={i} style={{ backgroundColor: '#FFF', padding: '15px', borderRadius: '15px', textAlign: 'center', boxShadow: '0 2px 5px rgba(0,0,0,0.05)' }}>
                <div style={{ fontSize: '24px', marginBottom: '5px' }}>{stat.icon}</div>
                <div style={{ fontSize: '18px', fontWeight: 'bold' }}>{stat.value}</div>
                <div style={{ fontSize: '10px', color: '#95A5A6', textTransform: 'uppercase' }}>{stat.label}</div>
              </div>
            ))}
          </div>

          <section>
            <h2 style={{ fontSize: '18px', marginBottom: '15px' }}>Vad vill du göra nu?</h2>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px' }}>
              <button style={actionButtonStyle}>
                <span style={{ fontSize: '24px', marginBottom: '8px' }}>📸</span>
                <span>Fota & Logga</span>
              </button>
              <button onClick={() => setActiveTab('convoy')} style={actionButtonStyle}>
                <span style={{ fontSize: '24px', marginBottom: '8px' }}>🫂</span>
                <span>Min Konvoj</span>
              </button>
            </div>
          </section>
        </div>
      );
    } 

    // 2. KONVOJ-VYN (Kolla hur kort denna blev nu!)
    else if (activeTab === 'convoy') {
      return <ConvoyView />; 
    } 

    // 3. LOGGBOKS-VYN
    else if (activeTab === 'logbook') {
      return (
        <div style={{ padding: '20px' }} className="animate-fade-in">
          <header style={{ marginBottom: '20px' }}>
            <h1 style={{ fontSize: '24px', fontWeight: 'bold', color: '#2D5A27', margin: 0 }}>Loggbok 📖</h1>
            <p style={{ color: '#636E72', marginTop: '5px' }}>Sommaren 2026 • 840 km totalt</p>
          </header>

          <button style={{ ...primaryBtnStyle, width: '100%', marginBottom: '30px', backgroundColor: '#D35400' }}>
            🎬 Exportera som TravelMap-film
          </button>

          <div style={{ borderLeft: '2px solid #DCEBDE', marginLeft: '20px', paddingLeft: '20px' }}>
            {logbookEntries.map((entry) => (
              <div key={entry.id} style={{ marginBottom: '25px', position: 'relative' }}>
                <div style={{ position: 'absolute', left: '-38px', top: '0', backgroundColor: '#FFF', width: '32px', height: '32px', borderRadius: '50%', display: 'flex', justifyContent: 'center', alignItems: 'center', border: '2px solid #DCEBDE', fontSize: '14px' }}>
                  {entry.icon}
                </div>
                <span style={{ fontSize: '12px', color: '#95A5A6', fontWeight: 'bold' }}>{entry.time}</span>
                <div style={{ backgroundColor: '#FFF', padding: '15px', borderRadius: '15px', marginTop: '5px', boxShadow: '0 2px 5px rgba(0,0,0,0.05)' }}>
                  <h3 style={{ margin: '0 0 5px 0', fontSize: '16px', color: '#2D3436' }}>{entry.title}</h3>
                  <p style={{ margin: 0, fontSize: '14px', color: '#636E72', lineHeight: '1.4' }}>{entry.desc}</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      );
    }
  };

  return (
    <div style={{ backgroundColor: '#F5F2ED', minHeight: '100vh', fontFamily: 'sans-serif', color: '#2D3436', position: 'relative', overflow: 'hidden', paddingBottom: '80px' }}>

      {renderContent()}

      {activeTab === 'home' && (
        <button onClick={() => setShowAssistant(true)} style={{ position: 'fixed', bottom: '100px', right: '20px', backgroundColor: '#D35400', color: 'white', border: 'none', padding: '15px', borderRadius: '50px', fontWeight: 'bold', cursor: 'pointer', boxShadow: '0 4px 10px rgba(0,0,0,0.2)', zIndex: 10 }}>
          🛑 Stopp
        </button>
      )}

      {/* Assistenten */}
      <div style={{ ...overlayStyle, opacity: showAssistant ? 1 : 0, pointerEvents: showAssistant ? 'auto' : 'none' }}>
        <div style={{ ...bottomSheetStyle, transform: showAssistant ? 'translateY(0)' : 'translateY(100%)' }}>
          <h2 style={{ fontSize: '22px', color: '#2D5A27', marginBottom: '5px', marginTop: '0' }}>Härlig plats! 🌲</h2>
          <p style={{ color: '#636E72', marginBottom: '25px', lineHeight: '1.5' }}>
            Jag känner att vi har stannat. Det är 18°C och soligt just nu. Vill du spara platsen i loggboken?
          </p>
          <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
            <button style={primaryBtnStyle}>☀️ Logga väder & plats</button>
            <button style={secondaryBtnStyle}>📸 Lägg till ett foto</button>
            <button style={secondaryBtnStyle}>🗺️ Dela med Konvojen</button>
          </div>
          <button onClick={() => setShowAssistant(false)} style={cancelBtnStyle}>Nej, vi ska bara sträcka på benen</button>
        </div>
      </div>

      {/* Bottenmeny */}
      <nav style={navBarStyle}>
        <button onClick={() => setActiveTab('home')} style={activeTab === 'home' ? activeNavItemStyle : navItemStyle}>
          <span style={{ fontSize: '24px' }}>🧭</span>
          <span style={{ fontSize: '10px', marginTop: '4px', fontWeight: activeTab === 'home' ? 'bold' : 'normal' }}>Hem</span>
        </button>
        <button onClick={() => setActiveTab('convoy')} style={activeTab === 'convoy' ? activeNavItemStyle : navItemStyle}>
          <span style={{ fontSize: '24px' }}>🫂</span>
          <span style={{ fontSize: '10px', marginTop: '4px', fontWeight: activeTab === 'convoy' ? 'bold' : 'normal' }}>Konvoj</span>
        </button>
        <button onClick={() => setActiveTab('logbook')} style={activeTab === 'logbook' ? activeNavItemStyle : navItemStyle}>
          <span style={{ fontSize: '24px' }}>📖</span>
          <span style={{ fontSize: '10px', marginTop: '4px', fontWeight: activeTab === 'logbook' ? 'bold' : 'normal' }}>Loggbok</span>
        </button>
      </nav>

    </div>
  );
}

// --- DESIGNMALLAR (STYLES) ---
const actionButtonStyle = { backgroundColor: '#2D5A27', color: 'white', border: 'none', padding: '20px', borderRadius: '20px', display: 'flex', flexDirection: 'column', alignItems: 'center', fontSize: '14px', fontWeight: '600', cursor: 'pointer' };
const overlayStyle = { position: 'fixed', top: 0, left: 0, right: 0, bottom: 0, backgroundColor: 'rgba(0,0,0,0.8)', display: 'flex', flexDirection: 'column', justifyContent: 'flex-end', zIndex: 1000, transition: 'opacity 0.5s ease-out' };
const bottomSheetStyle = { backgroundColor: '#FFF', padding: '30px 20px', borderTopLeftRadius: '30px', borderTopRightRadius: '30px', boxShadow: '0 -5px 20px rgba(0,0,0,0.1)', transition: 'transform 0.6s cubic-bezier(0.16, 1, 0.3, 1)' };
const primaryBtnStyle = { backgroundColor: '#2D5A27', color: 'white', border: 'none', padding: '16px', borderRadius: '15px', fontSize: '16px', fontWeight: 'bold', cursor: 'pointer' };
const secondaryBtnStyle = { backgroundColor: '#F5F2ED', color: '#2D3436', border: 'none', padding: '16px', borderRadius: '15px', fontSize: '16px', fontWeight: '600', cursor: 'pointer' };
const cancelBtnStyle = { width: '100%', padding: '20px 0 10px 0', backgroundColor: 'transparent', border: 'none', color: '#95A5A6', fontWeight: 'bold', cursor: 'pointer', fontSize: '14px', marginTop: '10px' };
const navBarStyle = { position: 'fixed', bottom: 0, left: 0, right: 0, backgroundColor: '#FFF', display: 'flex', justifyContent: 'space-around', padding: '10px 0 20px 0', boxShadow: '0 -2px 10px rgba(0,0,0,0.05)', zIndex: 100 };
const navItemStyle = { display: 'flex', flexDirection: 'column', alignItems: 'center', background: 'none', border: 'none', color: '#95A5A6', cursor: 'pointer', opacity: 0.5, transition: 'all 0.2s' };
const activeNavItemStyle = { ...navItemStyle, color: '#2D5A27', opacity: 1, transform: 'scale(1.05)' };

export default App;
